package dev.codedefense.cli;import dev.codedefense.ai.JdkProcessExecutor;import dev.codedefense.application.*;import dev.codedefense.change.*;import dev.codedefense.passport.*;import java.nio.file.Path;import java.util.concurrent.Callable;import picocli.CommandLine.*;
@Command(name="match",mixinStandardHelpOptions=true,description="Match an intact handoff to a local Git change.")public final class PassportHandoffMatchCommand implements Callable<Integer>{@Parameters(index="0")Path input;@Parameters(index="1",arity="0..1",defaultValue=".")Path repository;@Spec Model.CommandSpec spec;private final MatchChangeHandoffUseCase useCase;public PassportHandoffMatchCommand(){this(new MatchChangeHandoffUseCase(new FileSystemChangeHandoffStore(),new ChangeHandoffJsonCodec(),new GitCliChangeSource(new JdkProcessExecutor()),new ChangeHandoffTerminalRenderer()));}PassportHandoffMatchCommand(MatchChangeHandoffUseCase u){useCase=u;}public Integer call(){try{return useCase.match(input,repository,spec.commandLine().getOut(),spec.commandLine().getErr());}catch(ChangeHandoffPersistenceException e){spec.commandLine().getErr().println(e.getMessage());return ExitCodes.REPORT_PERSISTENCE_FAILED;}}}
